#include<bits/stdc++.h>
using namespace std;
const int N=1000010;
int n,tot;
int son[N][31],cnt[N],flag[N];
char ch[N];
void insert(string s)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        if(!son[p][x])
        {
            son[p][x]=++tot;
        }
        ch[son[p][x]]=x+'a';
        p=son[p][x];
    }
    cnt[p]++;
}
void update(string s)
{
    int p=0,len=s.size();
    for(int i=0;i<len;i++)
    {
        int x=s[i]-'a';
        flag[son[p][x]]=1;
        p=son[p][x];
    }
}
string ans;
int cnt1;
void dfs(int x)
{
    if(cnt[x]==1&&x!=0)
    {
        cnt1++;
        ans+="P";
    }
    if(cnt1==n)
    {
        printf("%d\n",ans.size());
        for(char i:ans)
        {
            printf("%c\n",i);
        }
        return;
    }
    for(int i=0;i<26;i++)
    {
        int v=son[x][i];
        if(!flag[v]&&v!=0)
        {
            ans+=ch[v];
            dfs(v);
            ans+="-";
        }
    }
    for(int i=0;i<26;i++)
    {
        int v=son[x][i];
        if(flag[v]&&v!=0)
        {
            ans+=ch[v];
            dfs(v);
            ans+="-";
        }
    }
}
int main()
{
    scanf("%d",&n);
    string l="";
    for(int i=1;i<=n;i++)
    {
        string s;
        cin>>s;
        insert(s);
        if(s.length()>l.length())
        {
            l=s;
        }
    }
    update(l);
    dfs(0);
    return 0;
}
